using Microsoft.EntityFrameworkCore;
using TeacherFind.Domain.Entities;
using TeacherFind.Infrastructure.Persistence;

namespace TeacherFind.Infrastructure.Persistence.Seed;

/// <summary>
/// Bölüm seed dosyası.
///
/// Kaynak SQL alanları: bolum_id, uni_id, bolum_ad, fakulte_id, status.
/// Faculty yapısı projeden kaldırıldığı için fakulte_id bilinçli olarak kullanılmadı.
/// Eski SQL içindeki 16469 satır, fakülte tekrarları temizlenerek 13311 benzersiz bölüm kaydına indirildi.
/// Eşleştirme üniversite adı üzerinden yapılır. Bu yüzden UniversitySeed önce çalışmalıdır.
/// </summary>
public static class DepartmentSeed
{
    public static async Task SeedAsync(AppDbContext context)
    {
        var universities = await context.Universities
            .AsNoTracking()
            .ToListAsync();

        var universityByName = universities
            .GroupBy(x => Normalize(x.Name))
            .ToDictionary(g => g.Key, g => g.First());

        var existingDepartments = await context.Departments
            .ToListAsync();

        var existingByCode = existingDepartments
            .Where(x => x.Code > 0)
            .GroupBy(x => x.Code)
            .ToDictionary(g => g.Key, g => g.First());

        var existingByUniversityAndName = existingDepartments
            .GroupBy(x => $"{x.UniversityId:N}|{Normalize(x.Name)}")
            .ToDictionary(g => g.Key, g => g.First());

        foreach (var seed in GetDepartments())
        {
            if (!universityByName.TryGetValue(Normalize(seed.UniversityName), out var university))
            {
                // Üniversite seed içinde yoksa bu bölüm atlanır.
                continue;
            }

            var key = $"{university.Id:N}|{Normalize(seed.Name)}";

            if (existingByCode.TryGetValue(seed.Code, out var department) ||
                existingByUniversityAndName.TryGetValue(key, out department))
            {
                department.Name = seed.Name;
                department.UniversityId = university.Id;
                department.IsActive = seed.IsActive;
            }
            else
            {
                department = new Department
                {
                    Code = seed.Code,
                    Name = seed.Name,
                    UniversityId = university.Id,
                    IsActive = seed.IsActive
                };

                context.Departments.Add(department);
                existingByCode[seed.Code] = department;
                existingByUniversityAndName[key] = department;
            }
        }

        await context.SaveChangesAsync();
    }

    private static string Normalize(string value)
    {
        return value.Trim().ToUpperInvariant();
    }

